const Q_PHYSICS_2022_MODEL_I=[{"id": "objective>Physics>2022 Model I>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following surfaces will absorb radiant energy best?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">white</div>", "<div style=\"font-family:Cambria;font-size:17px;\">red</div>", "<div style=\"font-family:Cambria;font-size:17px;\">yellow</div>", "<div style=\"font-family:Cambria;font-size:17px;\">black</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Black surfaces absorb radiant energy best. This is because black surfaces are good absorbers of heat and light. They absorb all wavelengths of light and convert them into heat, so the more light the object absorbs, the more heat it absorbs. This is why the color black is associated with absorption.</div>", "topic": "HEAT TRANSFER"}, {"id": "objective>Physics>2022 Model I>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In an electrolysis experiment, a cathode of mass 5g is found to weigh 5.01g after a current 10A flows for 50 seconds. What is the electrochemical equivalent of the deposited substance?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.00004g/C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.00002g/C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.026g/C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.0000125g/C</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">M = zit <br/> z = electrochemical equivalence <br/> 5.01 - 5.00 = 10 × 50 × z <br/> 0.01 = 500z <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">z</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.01<hr size=\"1\" />500</td></tr></table></div> <br/> z = 0.00002g/C</div>", "topic": "CURRENT ELECTRICITY: ELECTROLYSIS"}, {"id": "objective>Physics>2022 Model I>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A metal block of mass 10kg lies on a rough horizontal platform. If a horizontal force of 16N applied to the block through its centre of mass just slides the block on the platform, then the coefficient of limiting friction between the block and the platform is:</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.018</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.16</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.25</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.62</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The coefficient of limiting friction can be calculated using the formula: μ = F/mg, where F is the force required to just slide the block, m is the mass of the block, and g is the acceleration due to gravity. In this case, F = 16N, m = 10kg, and g = 9.8m/s^2. Substituting these values into the formula gives μ = 16N / (10kg * 9.8m/s^2) = 0.16. Therefore, the correct answer is 0.16.</div>", "topic": "FRICTION"}, {"id": "objective>Physics>2022 Model I>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A bus starts from rest and travels at a uniform acceleration of 2ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> for 25 seconds. What is the distance travelled?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">625m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">82m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12.5m</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">from second equation of motion  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">s</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">ut</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">at<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> u = 0, a = 2ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>, t = 25s <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">s</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0(25)</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">(2)</td><td style=\"text-align:center;\">(25<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>)</td></tr></table></div> <br/> s = 0 + 625 <br/> s = 625m</div>", "topic": "MOTION: LINEAR MOTION"}, {"id": "objective>Physics>2022 Model I>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An electrical appliance is rated 60V and has a resistance of 15Ω. What is the power consumption of the appliance?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">40W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">240W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">24W</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />R</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />15</td></tr></table></div> <br/> P = 240W</div>", "topic": "ELECTRICAL ENERGY AND POWER"}, {"id": "objective>Physics>2022 Model I>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The resultant of two forces is 50N. If the forces are perpendicular to each other and one of them makes an angle of 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> with the horizontal, find its magnitude.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">150N </div>", "<div style=\"font-family:Cambria;font-size:17px;\">75N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">43.3N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">57.74N</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span> = Fcos&#952; <br/>  <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span> = 50cos30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> <br/>  <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span> = 43.3N</div>", "topic": "EQUILIBRIUM OF FORCES"}, {"id": "objective>Physics>2022 Model I>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the workdone on an elastic spring with spring constant of 154Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, with initial length of 2m and a final length of 2.18m after being stretched by a force.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.5J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.4J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.18J</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">W</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">ke<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> k = 154Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>,e = 2.18 - 2 = 0.18m <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">W</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">154</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">0.18<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> W = 2.5J</div>", "topic": "ELASTICITY : WORK DONE IN SPRINGS AND ELASTIC STRINGS"}, {"id": "objective>Physics>2022 Model I>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object is weighted at different locations on the earth. What will be the right observation?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Both the mass and weight are constant.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Both the mass and weight vary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the mass is constant while the weight varies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the weight is constant while the mass varies</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The weight of a body is the resultant of earth's gravitational pull on it. The earth is not a perfect sphere, it is more flattened at the poles and bulges at the equator. Hence an object at the pole is closer to the earth's center than the one at the equator. The weight of a body at the poles should be more than that of when weighed at the equator. Thus the weight varies and the mass remains constant.</div>", "topic": "GRAVITATIONAL FIELD"}, {"id": "objective>Physics>2022 Model I>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a ray of sunlight passes obliquely through a rectangular glass block</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it emerges undeviated and undisplaced</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it gets dispersed into seven visible colours</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it deviates without dispersion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it gets laterally displaced and the emergent ray is parallel to the incident ray.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a ray of light passes through a rectangular glass, the emergent ray is parallel to the incident ray produced.</div>", "topic": "REFRACTION OF LIGHT THROUGH : GLASS PRISM"}, {"id": "objective>Physics>2022 Model I>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. the area of the plate <br/> II. the distance separating the plate <br/> III. the permittivity of dielectric <br/> IV. the mass of the plate <br/> The capacitance of a capacitor is dependent on which of the above?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I,II,III, and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III only</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The capacitance of a capacitor is dependent on the area of the plate,the distance separating them and the permitivity of dielectric</div>", "topic": "CAPACITORS : CAPACITANCE OF A CAPACITORS"}, {"id": "objective>Physics>2022 Model I>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A screw jack, 25% efficient and having a screw of pitch 0.4cm is used to raise a load through a certain height. If in the process the handle turns through a circle of radius 40cm, calculate the mechanical advantage of the machine. <br/> [π = 3.14]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">628</div>", "<div style=\"font-family:Cambria;font-size:17px;\">29</div>", "<div style=\"font-family:Cambria;font-size:17px;\">157</div>", "<div style=\"font-family:Cambria;font-size:17px;\">485</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Efficiency</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">M.A<hr size=\"1\" />V.R</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100%</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V.R</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">a</td><td style=\"text-align:center;\">screw</td><td style=\"text-align:center;\">jack</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2πr<hr size=\"1\" />p</td></tr></table></div>  <br/> r = radius of the circle or arm of the screw jack <br/> p = screw pitch <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V.R</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2πr<hr size=\"1\" />p</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V.R</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2×3.14×40<hr size=\"1\" />0.4</td></tr></table></div> <br/> V.R = 628 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">M.A<hr size=\"1\" />V.R</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">25<hr size=\"1\" />100</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">M.A<hr size=\"1\" />V.R</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />4</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">M.A</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V.R<hr size=\"1\" />4</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">M.A</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">628<hr size=\"1\" />4</td></tr></table></div> <br/> M.A = 157</div>", "topic": "SIMPLE MACHINES : EFFICIENCY OF MACHINES"}, {"id": "objective>Physics>2022 Model I>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A stone tied to a string is made to revolve in a horizontal circle of radius 4m with an angular speed of 2rad/s. With what tangential velocity will the stone move off the circle if the string cuts?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">16ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">8ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.5ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The tangential velocity (v) of an object moving in a circle is given by the formula v = rω, where r is the radius of the circle and ω is the angular speed. Substituting the given values, we get v = 4*2 = 8ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. Therefore, if the string cuts, the stone will move off the circle with a tangential velocity of 8ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>.</div>", "topic": "MOTION: MOTION IN A CIRCLE"}, {"id": "objective>Physics>2022 Model I>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements about wave is/are correct? <br/> I. A wavefront is a line which contains all particles whose vibrations are in phase. <br/> II. The direction of propagation of a wave is the line drawn parallel to the wavefront. <br/> III. A wavefront is a circle which is common to all particles that are in the same state of disturbance. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and III only</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A wavefront is a line which contains all particles whose vibrations are in phase and A wavefront is a circle which is common to all particles that are in the same state of disturbance, are correct.</div>", "topic": "WAVES : PRODUCTION AND PROPAGATION"}, {"id": "objective>Physics>2022 Model I>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following determine(s) the frequency of vibration of a stretched string? <br/> I. The length of the string  <br/> II. The density of the material of the string  <br/> III. The tension in the string</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II, and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II only</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The frequency of vibration of a stretched string is dependent on the length of the string, the density of the material of the string and the tension in the string.</div>", "topic": "PROPAGATION OF SOUND WAVES"}, {"id": "objective>Physics>2022 Model I>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A brass measuring tape is correct at 20<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C. The value obtained when the length of a field is measured with the rule at 50<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C appears to be 70.5m. What is the true length of the field? Linear expansivity of brass = 1.8 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">74.5m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60.95m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">70.46m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">70.96m</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">α</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>(θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>)</td></tr></table></div> <br/> l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 70.5, θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 50<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C, θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 20<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C, α = 1.8 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1.8×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">70.5-l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>(50-20)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1.8×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">70.5-l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />30l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td></tr></table></div> <br/> multiply both sides by 30l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> <br/> 1.8×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span> × 30l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 70.5-l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> <br/> 5.4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 70.5 - l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> <br/> 0.00054l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> + l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 70.5 <br/> 1.00054l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 70.5 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">70.5<hr size=\"1\" />1.00054</td></tr></table></div> <br/> l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 70.46m</div>", "topic": "HEAT TRANSFER: LINEAR EXPANSIVITY"}, {"id": "objective>Physics>2022 Model I>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements is an exception in the assumptions of the kinetic theory of gases?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The particles are in constant random motion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The intermolecular forces between particles are significant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The particles are of negligible size</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The particles collide with each other</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The kinetic-molecular theory of gases assumes that  <br/> - are constantly moving  <br/> - have negligible volume <br/> - have negligible intermolecular forces <br/> - undergo perfectly elastic collisions <br/> - have an average kinetic energy proportional to the ideal gas's absolute temperature <br/>  <br/> In the kinetic theory of gases, one key assumption is that intermolecular forces are negligible except during collisions. This means gas particles move freely without attraction or repulsion between them. <br/>  <br/> Thus, saying that \"the intermolecular forces between particles are significant\" contradicts this assumption.</div>", "topic": "STRUCTURE OF MATTER AND KINETIC THEORY : KINETIC THEORY"}, {"id": "objective>Physics>2022 Model I>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two strings of the same length and under the same tension gives notes of frequencies in the ratio 4 : 1. The masses of the strings are in the corresponding ratio of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2 : 1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 : 16</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 : 4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 : 2</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2L</td><td style=\"text-align:center;\">√</td><td style=\"text-align:center;\">T<hr size=\"1\" />m</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">√</td><td style=\"text-align:center;\">m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">√</td><td style=\"text-align:center;\">m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />16</td></tr></table></div></div>", "topic": "CHARACTERISTICS OF SOUND WAVES : OVERTONES PRODUCED BY VIBRATING STRINGS AND THEIR COLUMNS"}, {"id": "objective>Physics>2022 Model I>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A ball is kicked with an initial velocity of 25ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, if it comes to rest after 5seconds. Calculate the distance traveled.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">31.25m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">125m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">52.5m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">62.5m</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">from first equation of motion, v = u + at <br/> v = 0, u = 25ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, t =5s <br/> 0 = 25 + 5a <br/> 5a = -25 <br/> a = -5ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/> second equation <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">s</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">ut</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">at<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">s</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">25(5)</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">(-5)(5<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>)</td></tr></table></div> <br/> s = 125 - 62.5 <br/> s = 62.5m </div>", "topic": "MOTION: LINEAR MOTION"}, {"id": "objective>Physics>2022 Model I>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Heat is supplied to a test tube containing 100g of ice at its melting point. The ice melts completely in 1 min.What is the power rating of the source of heat? [Latent heat of fusion of ice = 336Jg-1]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">560W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">600W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">400W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">250W</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The power rating of the source of heat can be calculated using the formula P = Q/t, where Q is the heat supplied and t is the time. The heat supplied can be calculated using the formula Q = mL, where m is the mass of the substance and L is the latent heat of fusion. Substituting the given values, we get Q = 100g * 336J/g = 33600J. The time is given as 1 min, which is 60 seconds. Therefore, P = 33600J/60s = 560W. Hence, the correct option is 560W.</div>", "topic": "CHANGE OF STATE : SPECIFIC LATENT HEATS OF FUSION"}, {"id": "objective>Physics>2022 Model I>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A galvanometer of resistance 50 Ω which gives a full-scale deflection for 1mA, is to be adapted to measure currents up to 5A. Calculate the resistance of the resistor required.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.125Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.1Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.01Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.001Ω</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The current in the galvanometer is 1mA = 0.001A <br/> current in the required shunt = 5 - 0.001 = 4.999A <br/> the voltage across the shunt = 4.999 × R <br/> the voltage across the galvanometer = 0.001 × 50 = 0.05V <br/> since the p.d across shunt = p.d across the galvanometer resistance <br/> 0.005 = 4.999R <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.05<hr size=\"1\" />4.999</td></tr></table></div> <br/> R = 0.01Ω</div>", "topic": "MAGNETIC FIELD : CONVERSION OF GALVANOMETERS TO AMMETERS AND VOLTMETER"}, {"id": "objective>Physics>2022 Model I>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not true of a discharge tube?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The pressure of gas must be very low</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The glass tube must have two electrodes at the end</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The gas in the tube must be carbon dioxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Air is gradually pumped out of the tube</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A discharge tube can contain any type of gas, not necessarily carbon dioxide. The other options are true: the pressure of the gas must be very low, the glass tube must have two electrodes at the end, and air is gradually pumped out of the tube. Hence, the correct option is 'The gas in the tube must be carbon dioxide'.</div>", "topic": "CONDUCTION OF ELECTRICITY THROUGH : GASES"}, {"id": "objective>Physics>2022 Model I>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the time of flight of a projectile is 96seconds and it is fired at an angle of 60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> to the horizontal, calculate the horizontal range through the point of projection.  <br/> [take g =10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">84400m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">69000m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">26604m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">24000m</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Time of flight, T = 96s, θ =  60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">T</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2Usinθ<hr size=\"1\" />g</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">U</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">gT<hr size=\"1\" />2sinθ</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">U</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10×96<hr size=\"1\" />2sin60</td></tr></table></div> <br/> U = 554.26ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> R = (Ucosθ) × T <br/> R = 554.26cos60 × 96 <br/> R = 26604m <br/> R = 26.604km</div>", "topic": "MOTION: PROJECTILES"}, {"id": "objective>Physics>2022 Model I>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The diagram shows a uniform meter rule AB which balances horizontally at the 90cm mark when a mass of 0.2kg is suspended from B. Calculate the mass of the meter rule.  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.05kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.80kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.20kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.00kg</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">r</span>(90 - 50) = 0.2(100 - 90) <br/> 40M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">r</span> = 0.2(10) <br/> M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">r</span> = 2/40 <br/> M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">r</span> = 0.05kg</div>", "topic": "EQUILIBRIUM OF FORCES : PRINCIPLES OF MOMENTS"}, {"id": "objective>Physics>2022 Model I>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a source of sound is moving, a stationary listener will hear a sound of different frequency. This is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Doppler effect</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Resonance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Diffraction of sound</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rarefaction</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Doppler effect or Doppler shift is the change in frequency of a wave in relation to an observer who is moving relative to the wave source</div>", "topic": "PROPAGATION OF SOUND WAVES"}, {"id": "objective>Physics>2022 Model I>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following devices are used to measure pressure? <br/> i. Aneroid barometer.  <br/> ii. hydrometer.  <br/> iii. hygrometer.  <br/> iv. manometer.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">i and iii</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ii and iii</div>", "<div style=\"font-family:Cambria;font-size:17px;\">iii and iv</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i and iv</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pressure is measured using devices such as barometers and manometers. An aneroid barometer is a device used for measuring atmospheric pressure without the use of fluids. It operates using a small, flexible metal box called an aneroid cell. A manometer is a device used for measure the pressure of a gas or liquid. It usually consists of a U-shaped tube filled with a liquid. The pressure is determined by measuring the displacement of the liquid in the tube. Hydrometers and hygrometers are not used for measuring pressure. A hydrometer is used for determining the specific gravity of liquids, and a hygrometer is used for measuring humidity in the air.</div>", "topic": "PRESSURE : ATMOSPHERIC PRESSURE"}, {"id": "objective>Physics>2022 Model I>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the refractive index of glass is 1.5, what is the critical angle at the air-glass interface?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">41.8<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">61.8<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">34.6<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">51.3<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">refractive</td><td style=\"text-align:center;\">index(η)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />sinC</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">sin<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>(</td><td style=\"text-align:center;\">1<hr size=\"1\" />η</td><td style=\"text-align:center;\">)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">sin<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></td><td style=\"text-align:center;\">1<hr size=\"1\" />1.5</td></tr></table></div>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">sin<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></td><td style=\"text-align:center;\">2<hr size=\"1\" />3</td></tr></table></div> <br/> C = 41.8<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span></div>", "topic": "REFRACTION OF LIGHT THROUGH : GLASS PRISM"}, {"id": "objective>Physics>2022 Model I>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the final centigrade temperature required to change 20 litres of gas at 120<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C and 1 atmosphere to 25 litres at 2 atmosphere.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">709.5<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">509.5<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">909.5<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">729.6<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div>  <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 120<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C = 273 + 120 = 393K, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 20 litres, P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 1 atm, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 25 litres, P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 2 atm <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2×25×393<hr size=\"1\" />1×20</td></tr></table></div> <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 982.5K <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 982.5 - 273 = 709.5<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C</div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>2022 Model I>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A source of e.m.f of 50V with a frequency of 50Hz is connected to an inductor. What is the inductance of the inductor when a current of 10A passed through it?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.016H</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.015H</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.156H</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.0016H</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">V = IX<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<hr size=\"1\" />I</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">50<hr size=\"1\" />10</td></tr></table></div> <br/> X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span> = 5Ω <br/> X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span> = 2πfL <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">L</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span><hr size=\"1\" />2πf</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">L</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5<hr size=\"1\" />2(3.142)(50)</td></tr></table></div> <br/> L = 0.016H</div>", "topic": "SIMPLE A. C. CIRCUITS : INDUCTOR - INDUCTIVE REACTANCE"}, {"id": "objective>Physics>2022 Model I>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the length of the liquid column in a barometer tube that would support an atmospheric pressure of 102000Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> if the density of the liquid is 2600kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>? <br/> (g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10.75m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.76m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.92m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">39.23m</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pressure(P) = ρ × h × g <br/> P = 102000Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>, ρ = 2600kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>, g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/> 102000 = 2600 × h × 10 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">h</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">102000<hr size=\"1\" />26000</td></tr></table></div> <br/> h = 3.92m </div>", "topic": "PRESSURE : PRESSURE IN LIQUIDS"}, {"id": "objective>Physics>2022 Model I>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In 180 minutes, the activity of a certain radioactive substance falls to one-eight of its original value. Calculate its half.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">60 minutes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">90 minutes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30 minutes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20 minutes</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />8</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">N</td><td style=\"text-align:center;\">happened</td><td style=\"text-align:center;\">in</td><td style=\"text-align:center;\">180</td><td style=\"text-align:center;\">minutes</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">N</td><td style=\"text-align:center;\">------</td><td style=\"text-align:center;\">60</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">3</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">N</td><td style=\"text-align:center;\">-----</td><td style=\"text-align:center;\">60mins</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />4</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">N</td><td style=\"text-align:center;\">-----</td><td style=\"text-align:center;\">120mins</td><td style=\"text-align:center;\"></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />8</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">N</td><td style=\"text-align:center;\">-----</td><td style=\"text-align:center;\">180mins</td></tr></table></div> <br/> the half life is 60 mins</div>", "topic": "ELEMENTARY MODERN PHYSICS : HALF-LIFE AND DECAY CONSTANT"}, {"id": "objective>Physics>2022 Model I>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When three coplanar non-parallel forces are in equilibrium, <br/> I. They can be represented in magnitude and direction by the three sides of a triangle taken in order. <br/> II. Their lines of action meet at a point. <br/> III. The magnitude of any one force equals the magnitude of the resultant of the other two. <br/> IV. Any one force is the equilibriant of the other two. <br/> Which of the statements above are correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II, III and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II, III and IV</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When three coplanar non-parallel forces are in equilibrium: <br/> - They can be represented in magnitude and direction by the three sides of a triangle taken in order. <br/> - Their lines of action meet at a point. <br/> - The magnitude of any one force equals the magnitude of the resultant of the other two. <br/> - Any one force is the equilibriant of the other two.</div>", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES"}, {"id": "objective>Physics>2022 Model I>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following cannot be determined by a meter rule?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.56cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.25cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.50cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.05cm</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Meter rule has a reading accuracy of 0.5mm or 0.05cm, thus measurement is  M 0.05cm  <br/> the reading that cannot be read is 2.56cm</div>", "topic": "MEASUREMENTS AND UNITS : LIMITATIONS OF EXPERIMENTAL MEASUREMENTS"}, {"id": "objective>Physics>2022 Model I>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following explains the concave meniscus of water in a glass tube?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The adhesion between water and glass is greater than the cohesion between water molecules</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The cohesion between water molecules is greater than the adhesion between glass and water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The molecules of water near the glass are moving faster than the molecules in the other parts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The molecules of water at the water-air boundary are often attracted to the centre of the tube</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The concave meniscus of water in a glass tube is due to the adhesion between water and glass is greater than the cohesion between water molecules</div>", "topic": "STRUCTURE OF MATTER AND KINETIC THEORY : MOLECULAR NATURE OF MATTER"}, {"id": "objective>Physics>2022 Model I>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A temperature scale has a lower fixed point of 40mm and a upper fixed point of 200mm. What is the reading on this scale when a thermometer reads 60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">33.3mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">36.0mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">96.0mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">136.0mm</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">200mm ..... 100<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C <br/>  <br/> Xmm ..... 60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C <br/>  <br/> 40mm ..... 0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">x-40<hr size=\"1\" />200-40</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">60-0<hr size=\"1\" />100-0</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">x-40<hr size=\"1\" />160</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">60<hr size=\"1\" />100</td></tr></table></div> <br/> 10x - 400 = 960 <br/> 10x = 960 + 400 <br/> 10x = 1360 <br/> x = 136mm</div>", "topic": "TEMPERATURE AND ITS MEASUREMENT"}, {"id": "objective>Physics>2022 Model I>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major difference between a pure semiconductor and a pure metal is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">metals are harder than semiconductor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">while resistance of metals decrease with temperature , the reverse is the case for semiconductor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the resistance of metals increases with temperature, while for semiconductors, it is the reverse</div>", "<div style=\"font-family:Cambria;font-size:17px;\">metals have forbidden gaps while semiconductors have not</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Experiment shows that increase in temperature increases the resistance of a pure metal but decreases the resistance of pure semiconductor</div>", "topic": "INTRODUCTORY ELECTRONICS : METALS, SEMICONDUCTORS AND INSULATORS"}, {"id": "objective>Physics>2022 Model I>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a derived unit?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Newton</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Watt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Joule</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Second</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In physics, there are two types of units: base units and derived units. Base units are the fundamental units and cannot be broken down into simpler units. Derived units are formed by combining base units. Newton, Watt, and Joule are all derived units. Newton is the unit of force, Watt is the unit of power, and Joule is the unit of energy. Second, on the other hand, is a base unit. It is the base unit of time in the International System of Units.</div>", "topic": "MEASUREMENTS AND UNITS : FUNDAMENTAL PHYSICAL QUANTITIES"}, {"id": "objective>Physics>2022 Model I>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which statement describes nuclear fusion?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Two hydrogen nuclei join to form a helium nucleus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A helium nucleus joins with a hydrogen nucleus to form an alpha particle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Uranium nuclei split and produce high energy neutrons causing a chain reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Two helium nuclei join to form a hydrogen nucleus</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nuclear fusion is a reaction through which two or more light nuclei collide to form a heavier nucleus</div>", "topic": "ELEMENTARY MODERN PHYSICS : FUSION AND FISSION"}, {"id": "objective>Physics>2022 Model I>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is the dimension of pressure?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ML<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">MLT<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">ML<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">ML<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pressure(P) = ρ × h × g (or Pressure = F/A) <br/> ρ = mass/volume = ML<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/> h = L <br/> g = ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> = LT<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/> P = ML<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> × L × LT<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/> P = ML<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "topic": "MEASUREMENTS AND UNITS : DIMENSIONS"}, {"id": "objective>Physics>2022 Model I>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When the vapour of a substance is in equilibrium with its own liquid, it is said to be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gaseous</div>", "<div style=\"font-family:Cambria;font-size:17px;\">saturated</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diffused</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liquefied <br/> </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When the vapour of a substance is in equilibrium with its own liquid, it is said to be saturated. This is because the rate of evaporation is equal to the rate of condensation, meaning the amount of vapour is at its maximum for the given temperature and pressure.</div>", "topic": "CHANGE OF STATE~~VAPOURS : UNSATURATED AND SATURATED VAPOURS"}, {"id": "objective>Physics>2022 Model I>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> A body of mass 40kg is being dragged along the floor by a rope inclined at 60 degrees to the horizontal. The frictional force between the box and the floor is 100N and the tension on the rope is 300N. How much work is done by dragging the box for a distance of 4m</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">680J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">200J </div>", "<div style=\"font-family:Cambria;font-size:17px;\">400J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100J</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">T = 300 N <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">r</span> = 100 N <br/> Force acting on the box (F) = the horizontal component of the tension in the rope (T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span>) - the frictional force (F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">r</span>) <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span> = Tcos60 = 300cos60 = 150N <br/> F = 150 - 100 = 50N <br/> the workdone by F = 50N × 4m = 200J</div>", "topic": "WORK, ENERGY AND POWER"}];
